#nullable enable // autogenerated

using PVZEngine.Armors;
using PVZEngine.Buffs;
using PVZEngine.Callbacks;
using PVZEngine.Definitions;
using PVZEngine.Modifiers;
using UnityEngine;

namespace MVZ2.GameContent.Buffs.Armors
{
    [AutoBuffDefinition(VanillaBuffNames.Armor.darkMatterArmorInvisible)]
    public class DarkMatterArmorInvisibleBuff : BuffDefinition
    {
        public DarkMatterArmorInvisibleBuff(string nsp, string name) : base(nsp, name)
        {
            AddModifier(ColorModifier.Multiply(EngineArmorProps.TINT, new Color(1, 1, 1, 0)));
        }
    }
}
